import React, { useState, useEffect } from "react";
import {
  Container,
  Typography,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Grid,
  IconButton,
  Box,
} from "@mui/material";

import DeleteIcon from "@mui/icons-material/Delete";
import AddIcon from "@mui/icons-material/Add";

// Fake data — later replace with real data from backend / localStorage
const fakeDoctors = [
  {
    id: 101,
    name: "Dr. Suman Rai",
    specialty: "Internal Medicine",
    slots: ["Mon 9-11 AM", "Wed 2-4 PM"],
  },
  {
    id: 102,
    name: "Dr. Maya Thapa",
    specialty: "Physiotherapy",
    slots: ["Tue 10-12 PM", "Thu 3-5 PM"],
  },
];

const AdminDashboard = () => {
  const [doctors, setDoctors] = useState(fakeDoctors);
  const [open, setOpen] = useState(false);
  const [editingDoctor, setEditingDoctor] = useState(null);
  const [newSlot, setNewSlot] = useState("");

  const handleOpen = (doctor = null) => {
    setEditingDoctor(doctor);
    setNewSlot("");
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditingDoctor(null);
  };

  const handleAddSlot = () => {
    if (!newSlot.trim()) return alert("Please enter a slot time");

    const updatedDoctors = doctors.map((doc) =>
      doc.id === editingDoctor.id
        ? { ...doc, slots: [...doc.slots, newSlot.trim()] }
        : doc,
    );
    setDoctors(updatedDoctors);
    setNewSlot("");
  };

  const handleDeleteSlot = (doctorId, slotIndex) => {
    const updatedDoctors = doctors.map((doc) =>
      doc.id === doctorId
        ? { ...doc, slots: doc.slots.filter((_, i) => i !== slotIndex) }
        : doc,
    );
    setDoctors(updatedDoctors);
  };

  return (
    <Container maxWidth="lg" sx={{ py: 6 }}>
      <Typography
        variant="h4"
        gutterBottom
        align="center"
        sx={{ fontWeight: "bold", mb: 5 }}
      >
        Admin Dashboard – Manage Appointment Slots
      </Typography>

      <Paper elevation={3} sx={{ p: 4 }}>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>
                  <strong>Doctor Name</strong>
                </TableCell>
                <TableCell>
                  <strong>Specialty</strong>
                </TableCell>
                <TableCell>
                  <strong>Available Slots</strong>
                </TableCell>
                <TableCell align="right">
                  <strong>Actions</strong>
                </TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {doctors.map((doctor) => (
                <TableRow key={doctor.id}>
                  <TableCell>{doctor.name}</TableCell>
                  <TableCell>{doctor.specialty}</TableCell>
                  <TableCell>
                    {doctor.slots.length > 0 ? (
                      doctor.slots.map((slot, index) => (
                        <Box
                          key={index}
                          sx={{ display: "flex", alignItems: "center", mb: 1 }}
                        >
                          {slot}
                          <IconButton
                            size="small"
                            color="error"
                            onClick={() => handleDeleteSlot(doctor.id, index)}
                            sx={{ ml: 1 }}
                          >
                            <DeleteIcon fontSize="small" />
                          </IconButton>
                        </Box>
                      ))
                    ) : (
                      <Typography variant="body2" color="text.secondary">
                        No slots added
                      </Typography>
                    )}
                  </TableCell>
                  <TableCell align="right">
                    <Button
                      variant="outlined"
                      startIcon={<AddIcon />}
                      size="small"
                      onClick={() => handleOpen(doctor)}
                    >
                      Add Slot
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Dialog to add new slot */}
      <Dialog open={open} onClose={handleClose} maxWidth="sm" fullWidth>
        <DialogTitle>
          Add Availability Slot for {editingDoctor?.name}
        </DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            margin="dense"
            label="New Slot (e.g. Mon 9-11 AM)"
            fullWidth
            value={newSlot}
            onChange={(e) => setNewSlot(e.target.value)}
            sx={{ mt: 2 }}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={handleClose}>Cancel</Button>
          <Button onClick={handleAddSlot} variant="contained" color="primary">
            Add Slot
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default AdminDashboard;
